import { useState, useRef, useCallback, useEffect } from "react";
import { flushSync } from "react-dom";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/contexts/AuthContext";
import { useAIChatHistory } from "@/hooks/useAIChatHistory";
import type { AIRecipeSuggestion } from "@/hooks/useAIRecipe";

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_ANON_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
const IMAGE_URL = `${SUPABASE_URL}/functions/v1/ai-recipe/generate-images`;

// Location-related keywords in multiple languages
const LOCATION_KEYWORDS = [
  // 中文
  "最近", "附近", "离我", "距离", "远近", "近的", "周边", "周围", "最近的", "附近的",
  // 英文
  "nearest", "closest", "nearby", "near me", "close to me", "distance", "around me",
  // 葡萄牙语
  "mais perto", "próximo", "perto de mim", "distância", "mais próximo"
];

export interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
  isStreaming?: boolean;
}

export type Provider = "ask-xiaoxiong" | "xiaoxiong-agent" | "lovable-ai" | "xiaoxiong-community";

// Per-message recipe images: messageId -> recipe_name -> {url, loading}
export type RecipeImageMap = Record<string, Record<string, { url: string | null; loading: boolean }>>;

/** Extract recipe JSON blocks from message content */
export const extractRecipes = (content: string): AIRecipeSuggestion[] => {
  const recipes: AIRecipeSuggestion[] = [];
  const regex = /```recipe-json\s*\n([\s\S]*?)```/g;
  let match;
  while ((match = regex.exec(content)) !== null) {
    try {
      const parsed = JSON.parse(match[1].trim());
      if (parsed.recipe_name && parsed.ingredients && parsed.steps) {
        recipes.push(parsed as AIRecipeSuggestion);
      }
    } catch {
      // skip invalid JSON
    }
  }
  return recipes;
};

/** Remove recipe-json code blocks from display content */
export const stripRecipeJson = (content: string): string => {
  let stripped = content.replace(/```recipe-json\s*\n[\s\S]*?```/g, "");
  stripped = stripped.replace(/```recipe-json[\s\S]*/g, "");
  return stripped.trim();
};

/** Detect recipe/cooking intent from latest user input */
const isRecipeIntent = (text: string): boolean => {
  const normalized = text.toLowerCase().trim();
  if (!normalized) return false;
  return /教我|怎么做|做法|食谱|烧|炖|煮|炒|蒸|烤|recipe|how to cook|cook|receita|como fazer/.test(normalized);
};

/** Condense assistant messages for context: keep short memory markers, avoid replaying full old recipes */
const condenseAssistantForContext = (content: string): string => {
  const recipes = extractRecipes(content);
  const stripped = stripRecipeJson(content);

  if (recipes.length === 0) {
    if (stripped.length <= 420) return stripped;
    return stripped.slice(0, 220) + "\n...(内容省略)...\n" + stripped.slice(-120);
  }

  const recipeNames = Array.from(new Set(recipes.map(r => r.recipe_name).filter(Boolean))).join("、");
  return `[已提供完整食谱：${recipeNames}，不要再重复这些食谱]`;
};

const HISTORY_CONTEXT_LIMIT = 8;

/** Build compact context so model focuses on latest user intent */
const buildModelContextMessages = (historyMessages: Message[], latestUserContent: string) => {
  const filteredHistory = historyMessages.filter(m => m.content && !m.isStreaming);
  const latestIsRecipeIntent = isRecipeIntent(latestUserContent);

  // 对于“做菜/食谱”意图：移除历史 user 提问，避免模型把旧问题一起回答
  const contextHistory = (latestIsRecipeIntent
    ? filteredHistory.filter(m => m.role === "assistant")
    : filteredHistory
  ).slice(-HISTORY_CONTEXT_LIMIT);

  const chatMessages = contextHistory.map(m => ({
    role: m.role,
    content: m.role === "assistant" ? condenseAssistantForContext(m.content) : m.content,
  }));

  const allGivenRecipes = Array.from(new Set(
    contextHistory
      .filter(m => m.role === "assistant" && !!m.content)
      .flatMap(m => extractRecipes(m.content).map(r => r.recipe_name).filter(Boolean))
  ));

  const normalizedLatest = latestUserContent.replace(/\s+/g, " ").trim();
  let hardConstraint = "[对话约束：只回答我这一条最新消息，禁止复述历史问题。]";

  if (latestIsRecipeIntent) {
    hardConstraint = allGivenRecipes.length > 0
      ? `[对话约束：这是烹饪请求。本轮只允许回答“最后一条消息”涉及的菜名，禁止附带其他历史菜谱。历史已提供完整食谱：${allGivenRecipes.join("、")}（不要再重复这些食谱）。若用户再次点名历史菜，请只简短提醒“这道菜之前已经给过完整食谱”，不要再次输出完整步骤或 recipe-json。]`
      : `[对话约束：这是烹饪请求。本轮只允许回答“最后一条消息”涉及的菜名，禁止附带其他菜谱。]`;
  }

  chatMessages.push({ role: "user", content: `${normalizedLatest}\n\n${hardConstraint}` });
  return chatMessages;
};

// Get or create a random user ID for non-logged-in users
const getAnonymousUserId = (): string => {
  try {
    const storageKey = "xiaoxiong_anonymous_user_id";
    let anonymousId = localStorage.getItem(storageKey);
    if (!anonymousId) {
      anonymousId = `anon_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
      localStorage.setItem(storageKey, anonymousId);
    }
    return anonymousId;
  } catch {
    return `anon_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
  }
};

export const useXiaoxiongChat = (provider: Provider = "ask-xiaoxiong") => {
  const { i18n } = useTranslation();
  const { user } = useAuth();
  const { loadMessages, saveMessage, clearHistory, isLoadingHistory, historyLoaded } = useAIChatHistory("xiaoxiong");
  
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [showLocationDialog, setShowLocationDialog] = useState(false);
  const [pendingMessage, setPendingMessage] = useState<string | null>(null);
  const [recipeImages, setRecipeImages] = useState<RecipeImageMap>({});
  
  const abortControllerRef = useRef<AbortController | null>(null);
  const historyLoadedRef = useRef(false);

  /** Fetch images for recipes in a message */
  const fetchImagesForMessage = useCallback(async (messageId: string, recipes: AIRecipeSuggestion[]) => {
    if (recipes.length === 0) return;

    // Mark all as loading
    setRecipeImages(prev => ({
      ...prev,
      [messageId]: Object.fromEntries(recipes.map(r => [r.recipe_name, { url: null, loading: true }])),
    }));

    try {
      const resp = await fetch(IMAGE_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
        },
        body: JSON.stringify({ recipes }),
      });

      if (!resp.ok) throw new Error("Image generation failed");
      const data = await resp.json();
      const images: { recipe_name: string; image_url: string | null }[] = data.images || [];

      setRecipeImages(prev => ({
        ...prev,
        [messageId]: Object.fromEntries(
          images.map(img => [img.recipe_name, { url: img.image_url, loading: false }])
        ),
      }));
    } catch {
      setRecipeImages(prev => ({
        ...prev,
        [messageId]: Object.fromEntries(recipes.map(r => [r.recipe_name, { url: null, loading: false }])),
      }));
    }
  }, []);

  // Load chat history on mount
  useEffect(() => {
    if (!user?.id || historyLoadedRef.current) return;
    historyLoadedRef.current = true;
    loadMessages().then((history) => {
      if (history.length > 0) {
        const loadedMsgs = history.map((m, i) => ({
          id: `history_${i}`,
          role: m.role,
          content: m.content,
        }));
        setMessages(loadedMsgs);
        // Fetch recipe images for the last assistant message with recipes
        for (let i = loadedMsgs.length - 1; i >= 0; i--) {
          if (loadedMsgs[i].role === "assistant") {
            const recipes = extractRecipes(loadedMsgs[i].content);
            if (recipes.length > 0) {
              fetchImagesForMessage(loadedMsgs[i].id, recipes);
              break;
            }
          }
        }
      }
    });
  }, [user?.id, loadMessages, fetchImagesForMessage]);

  // Get user ID for agent provider
  const getUserId = useCallback((): string => {
    if (user?.id) {
      return user.id;
    }
    return getAnonymousUserId();
  }, [user?.id]);

  // Check if message needs location info
  const needsLocationInfo = useCallback((message: string): boolean => {
    const lowerMessage = message.toLowerCase();
    return LOCATION_KEYWORDS.some(keyword => lowerMessage.includes(keyword));
  }, []);

  const handleSubmitAskXiaoxiong = async (userMessage: Message, assistantMessageId: string) => {
    const response = await fetch(`${SUPABASE_URL}/functions/v1/ask-xiaoxiong`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'apikey': SUPABASE_ANON_KEY,
      },
      body: JSON.stringify({ 
        text: userMessage.content, 
        stream: true,
        lat: userLocation?.lat,
        lng: userLocation?.lng,
      }),
      signal: abortControllerRef.current?.signal,
    });

    if (!response.ok) {
      throw new Error(`Request failed with status: ${response.status}`);
    }

    if (!response.body) {
      throw new Error('No response body');
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let accumulatedResult = "";

    while (true) {
      const { done, value } = await reader.read();
      
      if (done) {
        break;
      }

      const chunk = decoder.decode(value, { stream: true });
      accumulatedResult += chunk;
      
      let cleanResult = accumulatedResult;
      if (cleanResult.startsWith('"')) {
        cleanResult = cleanResult.slice(1);
      }
      if (cleanResult.endsWith('"')) {
        cleanResult = cleanResult.slice(0, -1);
      }
      cleanResult = cleanResult.replace(/\\n/g, '\n');
      
      setMessages((prev) =>
        prev.map((msg) =>
          msg.id === assistantMessageId
            ? { ...msg, content: cleanResult }
            : msg
        )
      );
    }

    let finalResult = accumulatedResult;
    if (finalResult.startsWith('"')) {
      finalResult = finalResult.slice(1);
    }
    if (finalResult.endsWith('"')) {
      finalResult = finalResult.slice(0, -1);
    }
    finalResult = finalResult.replace(/\\n/g, '\n');
    
    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === assistantMessageId
          ? { ...msg, content: finalResult, isStreaming: false }
          : msg
      )
    );
  };

  const handleSubmitXiaoxiongAgent = async (userMessage: Message, assistantMessageId: string) => {
    const userId = getUserId();
    
    const response = await fetch(`${SUPABASE_URL}/functions/v1/xiaoxiong-agent`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'apikey': SUPABASE_ANON_KEY,
      },
      body: JSON.stringify({ 
        message: userMessage.content, 
        userId,
      }),
      signal: abortControllerRef.current?.signal,
    });

    if (!response.ok) {
      throw new Error(`Request failed with status: ${response.status}`);
    }

    if (!response.body) {
      throw new Error('No response body');
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let accumulatedResult = "";

    while (true) {
      const { done, value } = await reader.read();
      
      if (done) {
        break;
      }

      const chunk = decoder.decode(value, { stream: true });
      accumulatedResult += chunk;
      
      flushSync(() => {
        setMessages((prev) =>
          prev.map((msg) =>
            msg.id === assistantMessageId
              ? { ...msg, content: accumulatedResult }
              : msg
          )
        );
      });
      
      await new Promise(resolve => requestAnimationFrame(resolve));
    }

    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === assistantMessageId
          ? { ...msg, isStreaming: false }
          : msg
      )
    );
  };

  const handleSubmitLovableAI = async (userMessage: Message, assistantMessageId: string, isFirstMessage: boolean) => {
    const chatMessages = buildModelContextMessages(messages, userMessage.content);

    const response = await fetch(`${SUPABASE_URL}/functions/v1/lovable-chat`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'apikey': SUPABASE_ANON_KEY,
      },
      body: JSON.stringify({ 
        messages: chatMessages,
        lat: userLocation?.lat,
        lng: userLocation?.lng,
        language: i18n.language,
        isFirstMessage,
      }),
      signal: abortControllerRef.current?.signal,
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Request failed with status: ${response.status}`);
    }

    if (!response.body) {
      throw new Error('No response body');
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let accumulatedResult = "";
    let textBuffer = "";

    while (true) {
      const { done, value } = await reader.read();
      
      if (done) {
        break;
      }

      textBuffer += decoder.decode(value, { stream: true });

      let newlineIndex: number;
      while ((newlineIndex = textBuffer.indexOf("\n")) !== -1) {
        let line = textBuffer.slice(0, newlineIndex);
        textBuffer = textBuffer.slice(newlineIndex + 1);

        if (line.endsWith("\r")) line = line.slice(0, -1);
        if (line.startsWith(":") || line.trim() === "") continue;
        if (!line.startsWith("data: ")) continue;

        const jsonStr = line.slice(6).trim();
        if (jsonStr === "[DONE]") break;

        try {
          const parsed = JSON.parse(jsonStr);
          const content = parsed.choices?.[0]?.delta?.content as string | undefined;
          if (content) {
            accumulatedResult += content;
            
            flushSync(() => {
              setMessages((prev) =>
                prev.map((msg) =>
                  msg.id === assistantMessageId
                    ? { ...msg, content: accumulatedResult }
                    : msg
                )
              );
            });
            
            await new Promise(resolve => requestAnimationFrame(resolve));
          }
        } catch {
          // Ignore parsing errors
        }
      }
    }

    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === assistantMessageId
          ? { ...msg, isStreaming: false }
          : msg
      )
    );
  };

  const handleSubmitXiaoxiongCommunity = async (userMessage: Message, assistantMessageId: string, isFirstMessage: boolean) => {
    const chatMessages = buildModelContextMessages(messages, userMessage.content);

    const response = await fetch(`${SUPABASE_URL}/functions/v1/xiaoxiong-community`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'apikey': SUPABASE_ANON_KEY,
      },
      body: JSON.stringify({ 
        messages: chatMessages,
        includeContext: true,
        isFirstMessage,
      }),
      signal: abortControllerRef.current?.signal,
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Request failed with status: ${response.status}`);
    }

    if (!response.body) {
      throw new Error('No response body');
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let accumulatedResult = "";
    let textBuffer = "";

    while (true) {
      const { done, value } = await reader.read();
      
      if (done) {
        break;
      }

      textBuffer += decoder.decode(value, { stream: true });

      let newlineIndex: number;
      while ((newlineIndex = textBuffer.indexOf("\n")) !== -1) {
        let line = textBuffer.slice(0, newlineIndex);
        textBuffer = textBuffer.slice(newlineIndex + 1);

        if (line.endsWith("\r")) line = line.slice(0, -1);
        if (line.startsWith(":") || line.trim() === "") continue;
        if (!line.startsWith("data: ")) continue;

        const jsonStr = line.slice(6).trim();
        if (jsonStr === "[DONE]") break;

        try {
          const parsed = JSON.parse(jsonStr);
          const content = parsed.choices?.[0]?.delta?.content as string | undefined;
          if (content) {
            accumulatedResult += content;
            
            flushSync(() => {
              setMessages((prev) =>
                prev.map((msg) =>
                  msg.id === assistantMessageId
                    ? { ...msg, content: accumulatedResult }
                    : msg
                )
              );
            });
            
            await new Promise(resolve => requestAnimationFrame(resolve));
          }
        } catch {
          // Ignore parsing errors
        }
      }
    }

    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === assistantMessageId
          ? { ...msg, isStreaming: false }
          : msg
      )
    );
  };

  // Process and send message to AI
  const processMessage = useCallback(async (messageContent: string) => {
    // IMPORTANT: Check if this is the first message BEFORE adding new messages to state
    // This must be captured before setMessages is called
    const isFirstMessage = messages.length === 0;
    
    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content: messageContent,
    };

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: "assistant",
      content: "",
      isStreaming: true,
    };

    setMessages((prev) => [...prev, userMessage, assistantMessage]);
    setInput("");
    setIsLoading(true);

    // Save user message to history
    saveMessage("user", messageContent);

    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    abortControllerRef.current = new AbortController();

    try {
      if (provider === "xiaoxiong-community") {
        await handleSubmitXiaoxiongCommunity(userMessage, assistantMessageId, isFirstMessage);
      } else if (provider === "lovable-ai") {
        await handleSubmitLovableAI(userMessage, assistantMessageId, isFirstMessage);
      } else if (provider === "xiaoxiong-agent") {
        await handleSubmitXiaoxiongAgent(userMessage, assistantMessageId);
      } else {
        await handleSubmitAskXiaoxiong(userMessage, assistantMessageId);
      }
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') {
        console.log('Request aborted');
        return;
      }
      console.error("Ask API error:", err);
      const errorMessage =
        i18n.language === "zh"
          ? "抱歉，暂时无法获取结果，请稀后再试"
          : i18n.language === "pt"
          ? "Desculpe, não foi possível obter resultados. Tente novamente mais tarde."
          : "Sorry, unable to get results. Please try again later.";
      
      setMessages((prev) =>
        prev.map((msg) =>
          msg.id === assistantMessageId
            ? { ...msg, content: errorMessage, isStreaming: false }
            : msg
        )
      );
    } finally {
      setIsLoading(false);
      // Save assistant response to history and fetch recipe images
      setMessages((prev) => {
        const assistantMsg = prev.find(m => m.id === assistantMessageId);
        if (assistantMsg?.content) {
          saveMessage("assistant", assistantMsg.content);
          // Fetch recipe images if any
          const recipes = extractRecipes(assistantMsg.content);
          if (recipes.length > 0) {
            fetchImagesForMessage(assistantMessageId, recipes);
          }
        }
        return prev;
      });
    }
  }, [provider, userLocation, i18n.language, getUserId, messages.length, saveMessage, fetchImagesForMessage]);

  // Handle location permission confirmation
  const handleLocationConfirm = useCallback(() => {
    setShowLocationDialog(false);

    try {
      if (!navigator?.geolocation?.getCurrentPosition) {
        if (pendingMessage) {
          processMessage(pendingMessage);
          setPendingMessage(null);
        }
        return;
      }

      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
          if (pendingMessage) {
            setTimeout(() => {
              processMessage(pendingMessage);
              setPendingMessage(null);
            }, 100);
          }
        },
        (error) => {
          console.log("Location permission denied:", error.message);
          if (pendingMessage) {
            processMessage(pendingMessage);
            setPendingMessage(null);
          }
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
      );
    } catch (error) {
      console.warn("[useXiaoxiongChat] geolocation confirm failed:", error);
      if (pendingMessage) {
        processMessage(pendingMessage);
        setPendingMessage(null);
      }
    }
  }, [pendingMessage, processMessage]);

  const handleSubmit = useCallback(async () => {
    if (!input.trim() || isLoading) return;

    const messageContent = input.trim();

    if (!userLocation && needsLocationInfo(messageContent)) {
      setPendingMessage(messageContent);
      setShowLocationDialog(true);
      setInput("");
      return;
    }

    await processMessage(messageContent);
  }, [input, isLoading, userLocation, needsLocationInfo, processMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  }, [handleSubmit]);

  const abortRequest = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
  }, []);

  // Get initial location
  const requestLocation = useCallback(() => {
    try {
      if (!navigator?.geolocation?.getCurrentPosition) {
        return;
      }

      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => {
          console.log("Unable to get user location:", error.message);
        },
        { enableHighAccuracy: false, timeout: 5000, maximumAge: 300000 }
      );
    } catch (error) {
      console.warn("[useXiaoxiongChat] initial geolocation failed:", error);
    }
  }, []);

  const clearChat = useCallback(() => {
    // Optimistic clear first: avoid WebView freeze while waiting network
    setMessages([]);
    setRecipeImages({});

    void clearHistory().catch((error) => {
      console.error("Clear chat history failed:", error);
    });
  }, [clearHistory]);

  return {
    input,
    setInput,
    messages,
    isLoading,
    isLoadingHistory,
    showLocationDialog,
    setShowLocationDialog,
    pendingMessage,
    setPendingMessage,
    handleSubmit,
    handleKeyDown,
    handleLocationConfirm,
    processMessage,
    abortRequest,
    requestLocation,
    clearChat,
    recipeImages,
  };
};
